     6→/// Interceptor for handling authentication in API requests
     7→class AuthInterceptor extends Interceptor {
     8→  /// Add authentication token to requests
     9→  @override
    10→  void onRequest(
    11→    RequestOptions options,
    12→    RequestInterceptorHandler handler,
    13→  ) async {
    14→    // Skip authentication for login/register endpoints
    15→    if (_isAuthEndpoint(options.path)) {
    16→      return handler.next(options);
    17→    }
    18→
    19→    try {
    20→      // Get auth repository from service locator
    21→      final authRepository = getIt<AuthRepository>();
    22→
    23→      // Get access token
    24→      final token = await authRepository.getAccessToken();
    25→
    26→      if (token != null && token.isNotEmpty) {
    27→        // Add token to request headers
    28→        options.headers['Authorization'] = 'Bearer $token';
    29→      }
    30→
    31→      return handler.next(options);
    32→    } catch (e) {
    33→      debugPrint('Error in AuthInterceptor: $e');
    34→      return handler.next(options);
    35→    }
    36→  }
    37→
    38→  /// Handle authentication errors
    39→  @override
    40→  void onError(
    41→    DioException err,
    42→    ErrorInterceptorHandler handler,
    43→  ) async {
    44→    // Check if error is due to authentication
    45→    if (err.response?.statusCode == 401) {
    46→      try {
    47→        // Get auth repository from service locator
    48→        final authRepository = getIt<AuthRepository>();
    49→
    50→        // Try to refresh token
    51→        final session = await authRepository.refreshToken();
    52→
    53→        // Get new token from session
    54→        final newToken = session.accessToken;
    55→
    56→        if (newToken.isNotEmpty) {
    57→          // Create new request with updated token
    58→          final options = err.requestOptions;
    59→          options.headers['Authorization'] = 'Bearer $newToken';
    60→
    61→          // Retry request with new token
    62→          final response = await Dio().fetch(options);
    63→          return handler.resolve(response);
    64→        }
    65→
    66→        // If token refresh failed, proceed with error
    67→        return handler.next(err);
    68→      } catch (e) {
    69→        debugPrint('Error refreshing token: $e');
    70→        return handler.next(err);
    71→      }
    72→    }
    73→
    74→    // For other errors, proceed normally
    75→    return handler.next(err);
    76→  }
    77→
    78→  /// Check if the endpoint is an authentication endpoint
    79→  bool _isAuthEndpoint(String path) {
    80→    final authEndpoints = [
    81→      '/auth/login',
    82→      '/auth/register',
    83→      '/auth/forgot-password',
    84→      '/auth/reset-password',
    85→    ];
    86→
    87→    return authEndpoints.any((endpoint) => path.contains(endpoint));
    88→  }
    89→}
