     7→/// Interceptor for handling authentication in API requests
     8→class AuthInterceptor extends Interceptor {
     9→  /// Threshold for proactive token refresh (5 minutes)
    10→  static const _refreshThreshold = Duration(minutes: 5);
    11→
    12→  /// Flag to track if a refresh is currently in progress
    13→  bool _isRefreshing = false;
    14→
    15→  /// Add authentication token to requests
    16→  @override
    17→  void onRequest(
    18→    RequestOptions options,
    19→    RequestInterceptorHandler handler,
    20→  ) async {
    21→    // Skip authentication for login/register endpoints
    22→    if (_isAuthEndpoint(options.path)) {
    23→      return handler.next(options);
    24→    }
    25→
    26→    try {
    27→      // Get auth repository from service locator
    28→      final authRepository = getIt<AuthRepository>();
    29→
    30→      // Get current session to check expiration
    31→      final session = await authRepository.getSession();
    32→
    33→      if (session != null) {
    34→        // Check if token is expiring soon and needs proactive refresh
    35→        if (_shouldRefreshToken(session)) {
    36→          debugPrint('AuthInterceptor: Token expiring soon, triggering proactive refresh');
    37→
    38→          // Wait for in-progress refresh or start a new one
    39→          final newSession = await _performProactiveRefresh(authRepository);
    40→
    41→          // Use the new session if refresh was successful
    42→          if (newSession != null) {
    43→            options.headers['Authorization'] = 'Bearer ${newSession.accessToken}';
    44→            return handler.next(options);
    45→          }
    46→          // If refresh failed, continue with the existing token
    47→          // The server will return 401 if the token is expired, which will be handled in onError
    48→        }
    49→
    50→        // Add token to request headers
    51→        options.headers['Authorization'] = 'Bearer ${session.accessToken}';
    52→      }
    53→
    54→      return handler.next(options);
    55→    } catch (e) {
    56→      debugPrint('Error in AuthInterceptor: $e');
    57→      return handler.next(options);
    58→    }
    59→  }
    60→
    61→  /// Handle authentication errors
    62→  @override
    63→  void onError(
    64→    DioException err,
    65→    ErrorInterceptorHandler handler,
    66→  ) async {
    67→    // Check if error is due to authentication
    68→    if (err.response?.statusCode == 401) {
    69→      try {
    70→        // Get auth repository from service locator
    71→        final authRepository = getIt<AuthRepository>();
    72→
    73→        // Try to refresh token
    74→        final session = await authRepository.refreshToken();
    75→
    76→        // Get new token from session
    77→        final newToken = session.accessToken;
    78→
    79→        if (newToken.isNotEmpty) {
    80→          // Create new request with updated token
    81→          final options = err.requestOptions;
    82→          options.headers['Authorization'] = 'Bearer $newToken';
    83→
    84→          // Retry request with new token
    85→          final response = await Dio().fetch(options);
    86→          return handler.resolve(response);
    87→        }
    88→
    89→        // If token refresh failed, proceed with error
    90→        return handler.next(err);
    91→      } catch (e) {
    92→        debugPrint('Error refreshing token: $e');
    93→        return handler.next(err);
    94→      }
    95→    }
    96→
    97→    // For other errors, proceed normally
    98→    return handler.next(err);
    99→  }
   100→
   101→  /// Check if the endpoint is an authentication endpoint
   102→  bool _isAuthEndpoint(String path) {
   103→    final authEndpoints = [
   104→      '/auth/login',
   105→      '/auth/register',
   106→      '/auth/forgot-password',
   107→      '/auth/reset-password',
   108→    ];
   109→
   110→    return authEndpoints.any((endpoint) => path.contains(endpoint));
   111→  }
   112→
   113→  /// Checks if a token should be refreshed based on expiration time
   114→  bool _shouldRefreshToken(AuthSession session) {
   115→    // Check if token has no expiration information
   116→    if (session.expiresAt == DateTime(0)) {
   117→      return false;
   118→    }
   119→
   120→    // Calculate time until expiration
   121→    final timeUntilExpiration = session.expiresAt.difference(DateTime.now());
   122→
   123→    // Refresh if token expires in less than the threshold
   124→    return timeUntilExpiration < _refreshThreshold;
   125→  }
   126→
   127→  /// Performs a proactive token refresh
   128→  ///
   129→  /// This method implements a mutex-like pattern to ensure that only one
   130→  /// refresh operation is in progress at a time. Multiple concurrent requests
   131→  /// will wait for the same refresh operation to complete.
   132→  Future<AuthSession?> _performProactiveRefresh(AuthRepository authRepository) async {
   133→    // If a refresh is already in progress, wait for it to complete
   134→    if (_isRefreshing) {
   135→      debugPrint('AuthInterceptor: Refresh already in progress, waiting...');
   136→      // Wait a bit for the refresh to complete
   137→      await Future.delayed(const Duration(milliseconds: 100));
   138→
   139→      // Try to get the new session
   140→      try {
   141→        return await authRepository.getSession();
   142→      } catch (e) {
   143→        debugPrint('AuthInterceptor: Error waiting for refresh: $e');
   144→        return null;
   145→      }
   146→    }
   147→
   148→    // Start a new refresh operation
   149→    _isRefreshing = true;
   150→    try {
   151→      debugPrint('AuthInterceptor: Starting proactive token refresh');
   152→      final newSession = await authRepository.refreshToken();
   153→      debugPrint('AuthInterceptor: Proactive token refresh successful');
   154→      return newSession;
   155→    } catch (e) {
   156→      debugPrint('AuthInterceptor: Proactive token refresh failed: $e');
   157→      // Return null to indicate refresh failure
   158→      // The request will proceed with the old token and 401 will be handled if needed
   159→      return null;
   160→    } finally {
   161→      _isRefreshing = false;
   162→    }
   163→  }
   164→}
