    19→/// Scheduler for token refresh operations with app lifecycle awareness
    20→///
    21→/// This service manages token refresh scheduling by:
    22→/// - Scheduling refresh at 75% of token lifetime (via TokenExpirationTracker)
    23→/// - Respecting app lifecycle (pauses when app is backgrounded)
    24→/// - Waking up when app returns to foreground
    25→/// - Handling edge cases (app killed, network loss)
    26→class TokenRefreshScheduler extends WidgetsBindingObserver {
    27→  /// Tracker for monitoring token expiration
    28→  final TokenExpirationTracker _expirationTracker;
    29→
    30→  /// Current status of the scheduler
    31→  TokenRefreshSchedulerStatus _status = TokenRefreshSchedulerStatus.stopped;
    32→
    33→  /// Current auth session being monitored
    34→  AuthSession? _currentSession;
    35→
    36→  /// Binding observer registration flag
    37→  bool _isObserverRegistered = false;
    38→
    39→  /// Creates a new [TokenRefreshScheduler]
    40→  TokenRefreshScheduler({
    41→    required TokenExpirationTracker expirationTracker,
    42→  }) : _expirationTracker = expirationTracker;
    43→
    44→  /// Current status of the scheduler
    45→  TokenRefreshSchedulerStatus get status => _status;
    46→
    47→  /// Whether the scheduler is actively running
    48→  bool get isRunning => _status == TokenRefreshSchedulerStatus.running;
    49→
    50→  /// Whether the scheduler is paused
    51→  bool get isPaused => _status == TokenRefreshSchedulerStatus.paused;
    52→
    53→  /// Starts monitoring the token expiration for the given session
    54→  ///
    55→  /// This will schedule a refresh at 75% of the token lifetime and
    56→  /// register the app lifecycle observer to pause/resume monitoring.
    57→  void start(AuthSession session) {
    58→    debugPrint('TokenRefreshScheduler: Starting scheduler');
    59→
    60→    _currentSession = session;
    61→
    62→    // Register as observer if not already registered
    63→    if (!_isObserverRegistered) {
    64→      WidgetsBinding.instance.addObserver(this);
    65→      _isObserverRegistered = true;
    66→      debugPrint('TokenRefreshScheduler: Registered as WidgetsBindingObserver');
    67→    }
    68→
    69→    // Start tracking with the expiration tracker
    70→    _expirationTracker.startTracking(session);
    71→    _status = TokenRefreshSchedulerStatus.running;
    72→
    73→    debugPrint('TokenRefreshScheduler: Scheduler is now running');
    74→  }
    75→
    76→  /// Stops monitoring token expiration
    77→  ///
    78→  /// This will cancel any pending refresh operations and unregister
    79→  /// the app lifecycle observer.
    80→  void stop() {
    81→    debugPrint('TokenRefreshScheduler: Stopping scheduler');
    82→
    83→    _status = TokenRefreshSchedulerStatus.stopped;
    84→    _currentSession = null;
    85→
    86→    // Stop tracking with the expiration tracker
    87→    _expirationTracker.stopTracking();
    88→
    89→    // Unregister observer
    90→    if (_isObserverRegistered) {
    91→      WidgetsBinding.instance.removeObserver(this);
    92→      _isObserverRegistered = false;
    93→      debugPrint('TokenRefreshScheduler: Unregistered WidgetsBindingObserver');
    94→    }
    95→
    96→    debugPrint('TokenRefreshScheduler: Scheduler stopped');
    97→  }
    98→
    99→  /// Pauses the scheduler (e.g., when app goes to background)
   100→  ///
   101→  /// This keeps the session but stops the refresh timer.
   102→  void pause() {
   103→    if (_status != TokenRefreshSchedulerStatus.running) {
   104→      debugPrint('TokenRefreshScheduler: Cannot pause - scheduler is not running');
   105→      return;
   106→    }
   107→
   108→    debugPrint('TokenRefreshScheduler: Pausing scheduler');
   109→
   110→    _status = TokenRefreshSchedulerStatus.paused;
   111→
   112→    // Stop the tracking timer but keep the session
   113→    _expirationTracker.stopTracking();
   114→
   115→    debugPrint('TokenRefreshScheduler: Scheduler paused (timer stopped, session retained)');
   116→  }
   117→
   118→  /// Resumes the scheduler (e.g., when app returns to foreground)
   119→  ///
   120→  /// This restarts the refresh timer with the retained session.
   121→  void resume() {
   122→    if (_status != TokenRefreshSchedulerStatus.paused) {
   123→      debugPrint('TokenRefreshScheduler: Cannot resume - scheduler is not paused');
   124→      return;
   125→    }
   126→
   127→    if (_currentSession == null) {
   128→      debugPrint('TokenRefreshScheduler: Cannot resume - no session to track');
   129→      return;
   130→    }
   131→
   132→    debugPrint('TokenRefreshScheduler: Resuming scheduler');
   133→
   134→    // Restart tracking with the retained session
   135→    _expirationTracker.startTracking(_currentSession!);
   136→    _status = TokenRefreshSchedulerStatus.running;
   137→
   138→    debugPrint('TokenRefreshScheduler: Scheduler resumed and running');
   139→  }
   140→
   141→  /// Handles app lifecycle state changes
   142→  @override
   143→  void didChangeAppLifecycleState(AppLifecycleState state) {
   144→    debugPrint('TokenRefreshScheduler: App lifecycle state changed to $state');
   145→
   146→    switch (state) {
   147→      case AppLifecycleState.resumed:
   148→        // App returned to foreground
   149→        debugPrint('TokenRefreshScheduler: App resumed - checking if refresh needed');
   150→        _handleAppResumed();
   151→        break;
   152→
   153→      case AppLifecycleState.inactive:
   154→        // App is inactive (e.g., during a phone call)
   155→        debugPrint('TokenRefreshScheduler: App inactive - pausing scheduler');
   156→        pause();
   157→        break;
   158→
   159→      case AppLifecycleState.paused:
   160→        // App went to background
   161→        debugPrint('TokenRefreshScheduler: App paused - pausing scheduler');
   162→        pause();
   163→        break;
   164→
   165→      case AppLifecycleState.detached:
   166→        // App is being destroyed
   167→        debugPrint('TokenRefreshScheduler: App detached - stopping scheduler');
   168→        stop();
   169→        break;
   170→
   171→      case AppLifecycleState.hidden:
   172→        // App is hidden (same as background on most platforms)
   173→        debugPrint('TokenRefreshScheduler: App hidden - pausing scheduler');
   174→        pause();
   175→        break;
   176→    }
   177→  }
   178→
   179→  /// Handles app resume event
   180→  void _handleAppResumed() {
   181→    if (_currentSession == null) {
   182→      debugPrint('TokenRefreshScheduler: No session to monitor on resume');
   183→      return;
   184→    }
   185→
   186→    // Check if token needs immediate refresh
   187→    final expirationResult = _expirationTracker.checkExpiration(_currentSession!);
   188→
   189→    if (expirationResult.isExpired) {
   190→      debugPrint('TokenRefreshScheduler: Token is expired, immediate refresh needed');
   191→      // Resume will trigger immediate refresh if needed
   192→    } else if (expirationResult.shouldRefresh) {
   193→      debugPrint('TokenRefreshScheduler: Token should be refreshed soon');
   194→      // Resume will schedule refresh appropriately
   195→    } else {
   196→      final minutesUntilRefresh = expirationResult.timeUntilRefresh?.inMinutes ?? 0;
   197→      debugPrint('TokenRefreshScheduler: Token is valid, refresh in $minutesUntilRefresh minutes');
   198→    }
   199→
   200→    // Resume the scheduler
   201→    resume();
   202→  }
   203→
   204→  /// Updates the monitored session
   205→  ///
   206→  /// Use this when the session is updated externally (e.g., after a manual refresh).
   207→  /// This will reschedule the refresh timer based on the new expiration time.
   208→  void updateSession(AuthSession session) {
   209→    debugPrint('TokenRefreshScheduler: Updating monitored session');
   210→
   211→    _currentSession = session;
   212→
   213→    if (_status == TokenRefreshSchedulerStatus.running) {
   214→      // Update the tracker if we're running
   215→      _expirationTracker.updateSession(session);
   216→    } else if (_status == TokenRefreshSchedulerStatus.paused) {
   217→      // Just update the session, don't start tracking while paused
   218→      debugPrint('TokenRefreshScheduler: Session updated while paused');
   219→    }
   220→  }
   221→
   222→  /// Checks the expiration status of the current session
   223→  ///
   224→  /// Returns null if no session is being monitored.
   225→  TokenExpirationResult? checkExpiration() {
   226→    if (_currentSession == null) {
   227→      debugPrint('TokenRefreshScheduler: No session to check');
   228→      return null;
   229→    }
   230→
   231→    return _expirationTracker.checkExpiration(_currentSession!);
   232→  }
   233→
   234→  /// Disposes of the scheduler and cleans up resources
   235→  void dispose() {
   236→    debugPrint('TokenRefreshScheduler: Disposing scheduler');
   237→    stop();
   238→  }
   239→
   240→  /// Resets the scheduler state (useful for testing)
   241→  void reset() {
   242→    debugPrint('TokenRefreshScheduler: Resetting scheduler state');
   243→    stop();
   244→  }
   245→}
